pub struct SongLuaPlayerRuntimeWindows {
    pub constant_windows: Vec<AttackMaskWindow>,
    pub ease_windows: Vec<SongLuaEaseMaskWindow>,
    pub column_offsets: Vec<SongLuaColumnOffsetWindowRuntime>,
    pub unsupported_targets: usize,
}

pub fn build_song_lua_player_runtime_windows<ModWindow, EaseWindow, ColumnWindow>(
    time_mods: &[ModWindow],
    beat_mods: &[ModWindow],
    eases: &[EaseWindow],
    column_offset_windows: &[ColumnWindow],
    timing_player: &TimingData,
    player: usize,
    global_offset_seconds: f32,
    unsupported_ease: impl FnMut(&EaseWindow),
) -> SongLuaPlayerRuntimeWindows
where
    ModWindow: SongLuaModWindowLike,
    EaseWindow: SongLuaEaseWindowLike,
    ColumnWindow: SongLuaColumnOffsetWindowLike,
{
    let constant_windows = build_song_lua_constant_windows_for_player(
        time_mods,
        beat_mods,
        timing_player,
        player,
        global_offset_seconds,
    );
    let (ease_windows, unsupported_targets) = build_song_lua_ease_windows_for_player(
        eases,
        timing_player,
        player,
        global_offset_seconds,
        &constant_windows,
        unsupported_ease,
    );
    let column_offsets = build_song_lua_column_offset_windows_for_player(
        column_offset_windows,
        timing_player,
        player,
        global_offset_seconds,
    );
    SongLuaPlayerRuntimeWindows {
        constant_windows,
        ease_windows,
        column_offsets,
        unsupported_targets,
    }
}

pub fn song_lua_compile_player_screen_x(
    num_players: usize,
    player_index: usize,
    viewport: GameplayViewport,
    play_style: SongLuaCompilePlayStyle,
    single_player_uses_p2_side: bool,
    note_field_offset_x: f32,
    center_1player_notefield: bool,
) -> f32 {
    let clamped_width = viewport.width().clamp(640.0, 854.0);
    let centered_one_side = num_players == 1
        && play_style == SongLuaCompilePlayStyle::Single
        && center_1player_notefield;
    let centered_both_sides = num_players == 1 && play_style == SongLuaCompilePlayStyle::Double;
    let p2_side = if num_players == 1 {
        single_player_uses_p2_side
    } else {
        player_index == 1
    };
    let base_center_x = if num_players == 2 {
        if p2_side {
            viewport.center_x() + (clamped_width * 0.25)
        } else {
            viewport.center_x() - (clamped_width * 0.25)
        }
    } else if centered_both_sides || centered_one_side {
        viewport.center_x()
    } else if p2_side {
        viewport.center_x() + (clamped_width * 0.25)
    } else {
        viewport.center_x() - (clamped_width * 0.25)
    };
    if num_players == 1 && (centered_both_sides || centered_one_side) {
        viewport.center_x()
    } else {
        let offset_sign = if p2_side { 1.0 } else { -1.0 };
        base_center_x + offset_sign * note_field_offset_x.clamp(0.0, 50.0)
    }
}

pub fn song_lua_compile_player_screen_x_like<PlayStyle>(
    num_players: usize,
    player_index: usize,
    viewport: GameplayViewport,
    play_style: PlayStyle,
    single_player_uses_p2_side: bool,
    note_field_offset_x: f32,
    center_1player_notefield: bool,
) -> f32
where
    PlayStyle: SongLuaCompilePlayStyleLike,
{
    song_lua_compile_player_screen_x(
        num_players,
        player_index,
        viewport,
        play_style.as_song_lua_compile_play_style(),
        single_player_uses_p2_side,
        note_field_offset_x,
        center_1player_notefield,
    )
}

pub const MINI_PERCENT_MIN: f32 = -100.0;
pub const MINI_PERCENT_MAX: f32 = 150.0;

#[inline(always)]
pub fn effective_mini_percent(
    active_mini_percent: Option<f32>,
    fallback_mini_percent: f32,
    base_cleared: bool,
) -> f32 {
    let mini = active_mini_percent
        .filter(|v| v.is_finite())
        .unwrap_or(if base_cleared {
            0.0
        } else {
            fallback_mini_percent
        });
    mini.clamp(MINI_PERCENT_MIN, MINI_PERCENT_MAX)
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum MiniAttackMode {
    Absolute,
    Delta,
}

#[inline(always)]
pub fn attack_mini_target_percent(value: f32, mode: MiniAttackMode, base: f32) -> f32 {
    match mode {
        MiniAttackMode::Absolute => value,
        MiniAttackMode::Delta => base + value,
    }
}

#[inline(always)]
pub fn approach_attack_value(
    current: &mut Option<f32>,
    target: Option<f32>,
    base: f32,
    speed: Option<f32>,
    delta_time: f32,
    unit_scale: f32,
) {
    let Some(target) = target.filter(|value| value.is_finite()) else {
        *current = None;
        return;
    };
    if delta_time <= f32::EPSILON {
        *current = Some(target);
        return;
    }
    let Some(speed) = speed.filter(|value| value.is_finite()) else {
        *current = Some(target);
        return;
    };
    let step = delta_time.max(0.0) * speed.max(0.0) * unit_scale;
    if step <= f32::EPSILON {
        return;
    }
    let mut value = current.filter(|value| value.is_finite()).unwrap_or(base);
    approach_f32(&mut value, target, step);
    *current = Some(value);
}

#[inline(always)]
pub fn approach_attack_mini_percent_to_target(
    current: &mut Option<f32>,
    target: Option<f32>,
    base: f32,
    speed: Option<f32>,
    delta_time: f32,
) {
    approach_attack_value(current, target, base, speed, delta_time, 100.0);
    if let Some(value) = current.as_mut() {
        *value = value.clamp(MINI_PERCENT_MIN, MINI_PERCENT_MAX);
    }
}

#[inline(always)]
pub fn mini_value_for_percent(
    mini_percent: f32,
    fallback_mini_percent: f32,
    big_active: bool,
) -> f32 {
    let mut mini = if mini_percent.is_finite() {
        mini_percent
    } else {
        fallback_mini_percent
    };
    if big_active {
        // ITG _fallback/ArrowCloud map Effect Big to mod,-100% mini.
        mini -= 100.0;
    }
    mini.clamp(MINI_PERCENT_MIN, MINI_PERCENT_MAX) / 100.0
}

#[inline(always)]
pub fn mini_value_for_visual_mask(
    mini_percent: f32,
    fallback_mini_percent: f32,
    visual_mask: u16,
) -> f32 {
    mini_value_for_percent(
        mini_percent,
        fallback_mini_percent,
        (visual_mask & VISUAL_MASK_BIT_BIG) != 0,
    )
}

#[inline(always)]
pub fn player_draw_scale_for_mini(tilt: f32, mini_value: f32) -> f32 {
    (1.0 + 0.5 * tilt.abs()) * (1.0 + mini_value.abs())
}

#[inline(always)]
pub fn player_draw_scale_for_visual_mask(
    tilt: f32,
    mini_percent: f32,
    fallback_mini_percent: f32,
    visual_mask: u16,
) -> f32 {
    let mini = mini_value_for_visual_mask(mini_percent, fallback_mini_percent, visual_mask);
    player_draw_scale_for_mini(tilt, mini)
}

