pub struct GameplaySongLuaLayer<Compiled> {
    pub start_beat: f32,
    pub compiled: Compiled,
}

#[derive(Clone, Debug, PartialEq)]
pub struct GameplaySongLuaData<Compiled> {
    pub primary: Option<GameplayCompiledSongLua<Compiled>>,
    pub background_layers: Vec<GameplaySongLuaLayer<Compiled>>,
    pub foreground_layers: Vec<GameplaySongLuaLayer<Compiled>>,
}

impl<Compiled> Default for GameplaySongLuaData<Compiled> {
    fn default() -> Self {
        Self {
            primary: None,
            background_layers: Vec::new(),
            foreground_layers: Vec::new(),
        }
    }
}

fn extend_song_lua_sound_paths(out: &mut Vec<PathBuf>, paths: &[PathBuf]) {
    for path in paths {
        if !out.contains(path) {
            out.push(path.clone());
        }
    }
}

pub fn song_lua_sound_paths<Kind>(
    data: &GameplaySongLuaData<
        deadsync_song_lua::CompiledSongLua<deadsync_song_lua::SongLuaOverlayActor<Kind>>,
    >,
) -> Vec<PathBuf> {
    let mut out = Vec::new();
    if let Some(primary) = data.primary.as_ref() {
        extend_song_lua_sound_paths(&mut out, &primary.compiled.sound_paths);
    }
    for layer in data
        .background_layers
        .iter()
        .chain(data.foreground_layers.iter())
    {
        extend_song_lua_sound_paths(&mut out, &layer.compiled.sound_paths);
    }
    out
}

