    pub fn build_final_note_hit_plan(
        &mut self,
        player_idx: usize,
        hit: NoteHitEval,
        rate: f32,
    ) -> FinalNoteHitPlan {
        let judgment_offset_music_ns = self.live_autoplay_judgment_offset_music_ns(
            player_idx,
            hit.window,
            hit.measured_offset_music_ns,
        );
        final_note_hit_plan(hit, judgment_offset_music_ns, rate)
    }

