    #[test]
    fn column_flash_options_gate_grade_bits() {
        let options = ColumnFlashOptions {
            enabled: true,
            great: true,
            miss: true,
            ..ColumnFlashOptions::default()
        };

        assert!(column_flash_enabled_for_options(
            options,
            JudgeGrade::Great,
            false
        ));
        assert!(column_flash_enabled_for_options(
            options,
            JudgeGrade::Miss,
            false
        ));
        assert!(!column_flash_enabled_for_options(
            options,
            JudgeGrade::Excellent,
            false
        ));
        assert!(!column_flash_enabled_for_options(
            ColumnFlashOptions {
                enabled: false,
                great: true,
                ..ColumnFlashOptions::default()
            },
            JudgeGrade::Great,
            false
        ));
    }

